    <script>
        // ========== 核心工具 ==========
        function safeGet(obj, path, defaultValue = '') {
            if (!obj) return defaultValue;
            const keys = path.split('.');
            let current = obj;
            for (let key of keys) {
                if (current === null || current === undefined || typeof current !== 'object') return defaultValue;
                if (!(key in current)) return defaultValue;
                current = current[key];
            }
            return current === null || current === undefined ? defaultValue : current;
        }

        // ========== 数据获取 ==========
        async function fetchMvuData() {
            if (typeof Mvu !== 'undefined' && typeof Mvu.getMvuData === 'function') {
                try {
                    const result = Mvu.getMvuData({ type: 'message' });
                    return result.stat_data || result.data || result;
                } catch (e) { console.error("API error", e); }
            }

            if (typeof getVariables === 'function') {
                try {
                    const vars = getVariables({ type: 'message' });
                    return vars.stat_data || vars.data || vars;
                } catch (e) { console.error("API error", e); }
            }

            return null;
        }

        // ========== UI 更新 ==========
        async function updateUI() {
            const data = await fetchMvuData();
            if (!data) return;

            document.getElementById('status-loading').style.display = 'none';
            document.getElementById('status-ready').style.display = 'block';

            // 基础信息
            document.getElementById('ui-name').innerText = safeGet(data, '主角.基础信息.姓名', '无名者');
            document.getElementById('ui-race').innerText = safeGet(data, '主角.种族', '未知种族');
            document.getElementById('ui-job').innerText = safeGet(data, '主角.基础信息.职业', '游民');
            document.getElementById('ui-level').innerText = safeGet(data, '主角.基础信息.等级', '1');

            // 世界
            document.getElementById('ui-location').innerText = safeGet(data, '世界.地点', '虚空');
            document.getElementById('ui-season').innerText = safeGet(data, '世界.时间.季节', '未知季节');
            document.getElementById('ui-time').innerText = safeGet(data, '世界.时间.时段', '未知时段');
            document.getElementById('ui-threat').innerText = safeGet(data, '世界.威胁等级', '安全');

            // 状态条
            const hpCur = safeGet(data, '主角.状态.HP.当前', 0);
            const hpMax = safeGet(data, '主角.状态.HP.最大', 1);
            const mpCur = safeGet(data, '主角.状态.MP.当前', 0);
            const mpMax = safeGet(data, '主角.状态.MP.最大', 1);
            document.getElementById('ui-hp').innerText = `${hpCur}/${hpMax}`;
            document.getElementById('ui-mp').innerText = `${mpCur}/${mpMax}`;

            // 末日时钟
            const clock = safeGet(data, '世界.末日时钟', 1200);
            const clockPercent = (clock / 1440) * 100;
            document.getElementById('ui-clock-text').innerText = `${clock} / 1440`;
            document.getElementById('ui-clock-bar').style.width = `${clockPercent}%`;
            // 时钟变红逻辑
            if(clock < 60) document.getElementById('ui-clock-bar').style.backgroundColor = '#ff0000';

            // 觉醒度
            const awake = safeGet(data, '主角.奥法觉醒.觉醒度', 0);
            document.getElementById('ui-awake-text').innerText = `${awake}% (${safeGet(data, '主角.奥法觉醒.阶段描述', '休眠')})`;
            document.getElementById('ui-awake-bar').style.width = `${awake}%`;

            // 钱包
            document.getElementById('ui-gold').innerText = safeGet(data, '主角.钱包.金狮', 0);
            document.getElementById('ui-silver').innerText = safeGet(data, '主角.钱包.银辉', 0);
            document.getElementById('ui-copper').innerText = safeGet(data, '主角.钱包.铜叶', 0);

            // 装备
            const gear = safeGet(data, '物品.装备', {});
            let gearHtml = '';
            for (let [pos, name] of Object.entries(gear)) {
                if (pos.startsWith('_')) continue;
                gearHtml += `<div class="item-row"><span class="font-epic">${pos}:</span> <span>${name}</span></div>`;
            }
            document.getElementById('ui-equipment').innerHTML = gearHtml || '<div class="item-row">身无分文</div>';

            // 背包
            const inv = safeGet(data, '物品.背包', {});
            let invHtml = '';
            for (let [name, info] of Object.entries(inv)) {
                if (name.startsWith('_')) continue;
                const count = typeof info === 'object' ? (info.数量 || 1) : 1;
                const desc = typeof info === 'object' ? (info.描述 || '') : info;
                invHtml += `
                    <div class="item-row">
                        <div class="item-name">${name} x${count}</div>
                        <div class="item-desc">${desc}</div>
                    </div>`;
            }
            document.getElementById('ui-inventory').innerHTML = invHtml || '<div class="item-row">行囊空空</div>';
        }

        // ========== 交互逻辑 ==========
        function switchTab(tabId) {
            document.querySelectorAll('.nav-tab').forEach(t => t.classList.remove('active'));
            document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));

            event.currentTarget.classList.add('active');
            document.getElementById(tabId + '-tab').classList.add('active');

            if(tabId === 'status') updateUI();
        }

        function toggleRegion(header) {
            const isActive = header.classList.contains('active');
            document.querySelectorAll('.region-header').forEach(h => h.classList.remove('active'));
            if (!isActive) header.classList.add('active');
        }

        function toggleChoices() {
            document.getElementById('choice-panel').classList.toggle('active');
        }

        function initChoices() {
            const raw = document.querySelectorAll('.raw-choice');
            const list = document.getElementById('choice-list');
            const btn = document.getElementById('choice-btn');

            let choices = [];
            raw.forEach(r => {
                const text = r.innerText.trim();
                if(text && text !== '$' + r.dataset.idx) choices.push(text);
            });

            if(choices.length > 0) {
                btn.classList.remove('hidden');
                list.innerHTML = choices.map((c, i) => `
                    <div class="choice-item" onclick="copyChoice(this)">
                        <strong>${['I','II','III','IV','V'][i]}.</strong> ${c}
                    </div>
                `).join('');
            }
        }

        function copyChoice(el) {
            const text = el.innerText.split('. ')[1] || el.innerText;
            navigator.clipboard.writeText(text).then(() => {
                const original = el.style.backgroundColor;
                el.style.backgroundColor = '#e1f5fe';
                setTimeout(() => el.style.backgroundColor = original, 500);
            });
        }

        // 初始化
        window.onload = () => {
            updateUI();
            initChoices();
            // 定时刷新数据
            setInterval(updateUI, 5000);
        };
    </script>
</body>
</html>

