import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

const 品质 = z.enum(['common', 'rare', 'epic', 'legendary']);
const 时段 = z.enum(['清晨', '上午', '正午', '下午', '黄昏', '深夜']);
const 声望等级 = z.enum(['友善', '中立', '冷淡', '敌对', '通缉', '崇拜', '盟友']);
const 委托类型 = z.enum(['主线', '支线', '每日', '临危受命']);
const 委托状态 = z.enum(['未接取', '进行中', '已完成', '已失败']);
const 状态效果类型 = z.enum(['buff', 'debuff']);

export const Schema = z
  .object({
    主角: z
      .object({
        职业: z.string().prefault('普通冒险者'),
        信仰: z.string().prefault('无'),
        当前地点: z.string().prefault('中央翡翠平原'),
        称号: z.string().prefault('流浪的守夜人'),
        状态: z.string().prefault('健康'),
        临时状态: z
          .record(
            z.string().describe('状态名'),
            z.object({
              类型: 状态效果类型.prefault('buff'),
              描述: z.string().prefault(''),
            }),
          )
          .prefault({}),
        货币: z
          .object({
            金狮: z.coerce.number().transform(v => _.clamp(v, 0, 1e9)).prefault(0),
            银辉币: z.coerce.number().transform(v => _.clamp(v, 0, 1e9)).prefault(0),
            铜叶币: z.coerce.number().transform(v => _.clamp(v, 0, 1e9)).prefault(0),
            以太结晶: z.coerce.number().transform(v => _.clamp(v, 0, 1e6)).prefault(0),
          })
          .prefault({}),
        生命: z.coerce.number().transform(v => _.clamp(v, 0, 9999)).prefault(340),
        生命上限: z.coerce.number().transform(v => _.clamp(v, 1, 9999)).prefault(450),
        法力: z.coerce.number().transform(v => _.clamp(v, 0, 9999)).prefault(120),
        法力上限: z.coerce.number().transform(v => _.clamp(v, 1, 9999)).prefault(200),
        奥法之灾觉醒度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(45),
        奥法之灾觉醒度上限: z.coerce.number().transform(v => _.clamp(v, 1, 100)).prefault(100),
        装备栏: z
          .record(
            z.enum(['主手', '副手', '服饰', '饰品']),
            z
              .object({
                装备名: z.string().prefault('空置'),
                描述: z.string().prefault(''),
                品质: 品质.prefault('common'),
              })
              .prefault({}),
          )
          .prefault(() => ({ 主手: {}, 副手: {}, 服饰: {}, 饰品: {} })),
        物品栏: z
          .record(
            z.string().describe('物品名'),
            z.object({
              描述: z.string().prefault(''),
              数量: z.coerce.number().transform(v => _.clamp(v, 0, 999999)),
              品质: 品质.prefault('common'),
            }),
          )
          .transform(data => _.pickBy(data, ({ 数量 }) => 数量 > 0))
          .prefault({}),
      })
      .prefault({}),

    世界: z
      .object({
        纪元: z.string().prefault('暗影纪元'),
        月: z.coerce.number().transform(v => _.clamp(v, 1, 12)).prefault(1),
        日: z.coerce.number().transform(v => _.clamp(v, 1, 31)).prefault(1),
        时段: 时段.prefault('上午'),
        末日时钟刻度: z.coerce.number().transform(v => _.clamp(v, 1, 12)).prefault(3),
        委托等级: z.string().prefault('铜牌'),
      })
      .prefault({}),

    小队: z
      .record(
        z.string().describe('成员名'),
        z.object({
          职业: z.string().prefault(''),
          生命: z.coerce.number().transform(v => _.clamp(v, 0, 9999)).prefault(0),
          生命上限: z.coerce.number().transform(v => _.clamp(v, 1, 9999)).prefault(1),
          状态: z.string().prefault(''),
        }),
      )
      .prefault({}),

    人际关系: z
      .record(
        z.string().describe('NPC名'),
        z.object({
          好感度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
          关系: z.string().prefault(''),
          描述: z.string().prefault(''),
        }),
      )
      .prefault({}),

    势力: z
      .record(
        z.string().describe('势力名'),
        z.object({
          声望: 声望等级.prefault('中立'),
          描述: z.string().prefault(''),
        }),
      )
      .prefault({}),

    委托列表: z
      .record(
        z.string().describe('委托名'),
        z.object({
          类型: 委托类型.prefault('支线'),
          说明: z.string().prefault(''),
          目标: z.string().prefault(''),
          奖励: z.string().prefault(''),
          惩罚: z.string().prefault(''),
          状态: 委托状态.prefault('未接取'),
        }),
      )
      .prefault({}),
  })
  .prefault({});

$(() => {
  registerMvuSchema(Schema);
});

$(() => {
  // 移除除了最后一楼以外的楼层
  $('#chat > .mes').not('.last_mes').remove();

  // 当聊天文件变更时, 重新加载前端界面或脚本
  let current_chat_id = SillyTavern.getCurrentChatId();
  eventOn(tavern_events.CHAT_CHANGED, chat_id => {
    if (current_chat_id !== chat_id) {
      current_chat_id = chat_id;
      reloadIframe();
    }
  })
})

